<?php
namespace App\Http\Controllers; use App\Models\KnowledgeMachine; use Illuminate\Http\{JsonResponse,Request,Response}; use Illuminate\Validation\Rule;
class KnowledgeMachineController extends Controller { public function index(Request $r):JsonResponse{$q=KnowledgeMachine::with('media')->where('is_active',true);if($r->filled('search')){$s=$r->search;$q->where(fn($x)=>$x->where('manufacturer','like',"%$s%")->orWhere('model_name','like',"%$s%")->orWhere('variant','like',"%$s%"));}if($r->filled('manufacturer'))$q->where('manufacturer',$r->manufacturer);return response()->json($q->orderBy('manufacturer')->orderBy('model_name')->get());} public function store(Request $r):JsonResponse{$this->manage($r);$d=$this->validated($r);$d['created_by']=$d['updated_by']=$r->user()->id;return response()->json(KnowledgeMachine::create($d),201);} public function show(KnowledgeMachine $knowledgeMachine):JsonResponse{return response()->json($knowledgeMachine->load(['notes.media','media','documents']));} public function update(Request $r,KnowledgeMachine $knowledgeMachine):JsonResponse{$this->manage($r);$d=$this->validated($r,true);$d['updated_by']=$r->user()->id;$knowledgeMachine->update($d);return response()->json($knowledgeMachine->fresh());} public function destroy(Request $r,KnowledgeMachine $knowledgeMachine):Response{$this->manage($r);$knowledgeMachine->update(['is_active'=>false,'updated_by'=>$r->user()->id]);return response()->noContent();} private function manage(Request $r):void{abort_unless($r->user()->role==='admin',403);} private function validated(Request $r,bool $partial=false):array{$x=$partial?'sometimes|required':'required';return $r->validate(['manufacturer'=>[$x,'string','max:255'],'model_name'=>[$x,'string','max:255'],'variant'=>['sometimes','nullable','string','max:255'],'product_code'=>['sometimes','nullable','string','max:255',Rule::unique('knowledge_machines')->ignore($r->route('knowledgeMachine'))],'category'=>['sometimes','nullable','string','max:255'],'summary'=>['sometimes','nullable','string'],'supported_refrigerants'=>['sometimes','nullable','array'],'supported_refrigerants.*'=>['string','max:50'],'technical_specifications'=>['sometimes','nullable','array'],'main_functions'=>['sometimes','nullable','array'],'is_active'=>['sometimes','boolean']]);}}
